CREATE OR REPLACE FUNCTION fpa_get_memname_by_old_conno (as_old_conno char) RETURNS varchar AS $body$
DECLARE

  ls_value varchar(100);
  ls_memno sc_mem_m_membership_registered.membership_no% TYPE;

BEGIN

  select  membership_no into STRICT ls_memno
  from    sc_lon_m_contract
  where	  loan_contract_no = as_old_conno;

  ls_value := ls_memno ||' '||pka_com_function.fp_get_member_name(trim(both ls_memno));

  if length(trim(both ls_value)) > 0 then
     return ls_value;
  else
     return null;
  end if;

end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
